/*global QUnit,sinon*/

sap.ui.define([
	"sap/suite/ui/commons/demo/tutorial/controller/ProcessFlow.controller",
	"sap/m/MessageToast",
	"sap/base/i18n/ResourceBundle",
	"sap/ui/thirdparty/sinon",
	"sap/ui/thirdparty/sinon-qunit"
], function(ProcessFlowController, MessageToast, ResourceBundle) {
	"use strict";

	QUnit.module("ProcessFlow Controller - getValuesDelta formatter", {
		beforeEach: function() {
			this.oController = new ProcessFlowController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("should return the delta with measure", function(assert) {
		var sResult = this.oController.getValuesDelta(5, 3, "%");
		assert.equal(sResult, "-2", "Correct string returned");
	});

	QUnit.module("ProcessFlow Controller - onNodePressed event handler", {
		beforeEach: function() {
			function getResourceBundle() {
				return ResourceBundle.create({ url: "../i18n/i18n.properties", async: true });
			}

			this.oController = new ProcessFlowController();
			this.oController.getOwnerComponent = function() {
				return {
					getModel: function() {
						return {
							getResourceBundle: getResourceBundle
						};
					}
				};
			};
			this.oEventMock = {
				getParameters: function() {
					return {
						getTitle: function () {
							return "Title";
						}
					};
				}
			};
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("Node title should be part of the message toast text", function(assert) {
		var oSpy = sinon.spy(MessageToast, "show"),
			done = assert.async();
		this.oController.onNodePressed(this.oEventMock);
		setTimeout(function() {
			assert.ok(oSpy.calledWith("The node \"Title\" is clicked"), "MessageToast shown with correct text");
			oSpy.restore();
			done();
		},500)
	});
});

/*global QUnit,sinon*/

sap.ui.define([
	"sap/suite/ui/commons/demo/tutorial/controller/Reviews.controller",
	"sap/ui/thirdparty/sinon",
	"sap/ui/thirdparty/sinon-qunit"
], function(ReviewsController) {
	"use strict";

	QUnit.module("Reviews Controller - onHorizontalSwitchChange event handler", {
		beforeEach: function() {
			this.getParameter = function() {
				return true;
			};
			this.oEventMock = {
				getParameter: this.getParameter
			};
			this.oController = new ReviewsController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("Property changed according to switch state in timeline control - horizontal", function(assert) {
		var oTimeLineMock = {
			setAxisOrientation: setAxisOrientation
		};
		this.oController.oTimeline = oTimeLineMock;
		this.oController.onHorizontalSwitchChange(this.oEventMock);
		function setAxisOrientation(value) {
			assert.equal(value, "Horizontal", "Property 'AxisOrientation' correctly set");
		}
	});

	QUnit.test("Property changed according to switch state in timeline control - vertical", function(assert) {
		var oTimeLineMock = {
			setAxisOrientation: setAxisOrientation
		};
		this.oController.oTimeline = oTimeLineMock;
		this.oEventMock.getParameter = function () {
			return false;
		};
		this.oController.onHorizontalSwitchChange(this.oEventMock);
		function setAxisOrientation(value) {
			assert.equal(value, "Vertical", "Property 'AxisOrientation' correctly set");
		}
	});

	QUnit.module("Reviews Controller - formatDateTime formatter", {
		beforeEach: function() {
			this.oController = new ReviewsController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});
});

/*global QUnit,sinon*/

sap.ui.define([
	"sap/suite/ui/commons/demo/tutorial/controller/Startpage.controller",
	"sap/m/MessageToast",
	"sap/base/i18n/ResourceBundle",
	"sap/ui/thirdparty/sinon",
	"sap/ui/thirdparty/sinon-qunit"
], function(StartpageController, MessageToast, ResourceBundle) {
	"use strict";

	QUnit.module("Launchpad Controller - formatJSONDate formatter", {
		beforeEach: function() {
			this.oController = new StartpageController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("JSON date is formatted to local date string", function(assert) {
		assert.equal(this.oController.formatJSONDate("2016-12-06T00:00:00.000Z"), new Date("2016-12-06T00:00:00.000Z").toLocaleDateString(), "Formatted as local date string");
	});

	QUnit.module("Launchpad Controller - formatNumber formatter", {
		beforeEach: function() {
			this.oController = new StartpageController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.module("Launchpad Controller - getProgress formatter", {
		beforeEach: function() {
			this.oController = new StartpageController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("should return 0 if nodes are undefined", function(assert) {
		var aNodes = null;
		var oResult = this.oController.getProgress(aNodes);
		assert.equal(oResult, 0, "0 is returned");
	});

	QUnit.test("should return 0 in nodes collection empty", function(assert) {
		var aNodes = [];
		var oResult = this.oController.getProgress(aNodes);
		assert.equal(oResult, 0, "0 is returned");
	});

	QUnit.test("should return 0 if no node with positive state defined", function(assert) {
		var aNodes = [{ state: "unknown" }, { state: "unknown" }];
		var oResult = this.oController.getProgress(aNodes);
		assert.equal(oResult, 0, "0 is returned");
	});

	QUnit.test("should return 50 if one of two nodes has the state \"Positive\"", function(assert) {
		var aNodes = [{ state: "unknown" }, { state: "Positive" }];
		var oResult = this.oController.getProgress(aNodes);
		assert.equal(oResult, 50, "50 is returned");
	});

	QUnit.test("should return 100 if all nodes have the state \"Positive\"", function(assert) {
		var aNodes = [{ state: "Positive" }, { state: "Positive" }];
		var oResult = this.oController.getProgress(aNodes);
		assert.equal(oResult, 100, "100 is returned");
	});

	QUnit.module("Launchpad Controller - onInit hook", {
		beforeEach: function() {
			this.oController = new StartpageController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("Init method creates model", function(assert) {
		this.oController.getView = function() {
			return {
				setModel: setModel
			};
		};
		this.oController.onInit();

		function setModel(model, name) {
			assert.equal(model.getMetadata().getName(), "sap.ui.model.json.JSONModel", "JSON model created");
			assert.equal(name, "news", "JSON model under name 'news' assigned");
		}
	});

	QUnit.module("Launchpad Controller - getEntityCount formatter", {
		beforeEach: function() {
			this.oController = new StartpageController();
		},
		afterEach: function() {
			this.oController.destroy();
		}
	});

	QUnit.test("'0' returned in case no parameter is provided", function(assert) {
		assert.equal(this.oController.getEntityCount(), 0);
	});

	QUnit.test("'1' returned in case one entry is inside the array", function(assert) {
		assert.equal(this.oController.getEntityCount(["TestData"]), 1);
	});

	QUnit.module("Launchpad Controller - onTilePressed event handler", {
		beforeEach: function() {
			function getResourceBundle() {
				return ResourceBundle.create({ url: "../i18n/i18n.properties", async: true });
			}

			this.oController = new StartpageController();
			this.oController.getOwnerComponent = function() {
				return {
					getModel: function() {
						return {
							getResourceBundle: getResourceBundle
						};
					}
				};
			};
			this.getHeader = function() {
				return "Header";
			};
			this.getSubheader = function() {
				return "Subheader";
			};
			this.oEventMock = {
				getSource: function() {
					return {
						getHeader: this.getHeader,
						getSubheader: this.getSubheader
					};
				}.bind(this)
			};
			this.oSpy = sinon.spy(MessageToast, "show");
		},
		afterEach: function() {
			this.oController.destroy();
			this.oSpy.restore();
		}
	});

	QUnit.test("If header and subheader are present, only header is part of the message toast text", function(assert) {
		var done = assert.async();
